   .sort((a, b) => new Date(a.occurred_at) - new Date(b.occurred_at));\n  const ownerRouting = ownerGroups.map((item) => item.owner_group).join(\" + \");\n  const recoveryOwner = ownerGroups[ownerGroups.length - 1]?.owner_group || null;\n  const timelineSummary = activities.map((item) => `${item.occurred_at} ${item.summary}`).join(\" | \");\n\n  replaceRows(db.workflow_state, request.request_id, [{\n    workflow_state_id: `state-${request.request_id}`,\n    request_id: request.request_id,\n    task_id: request.task_id,\n    account_id: request.account_id,\n    title: request.title,\n    status: request.expected_outcome,\n    next_step: request.next_step,\n    customer_message: request.customer_message,\n    account_name: account?.name || null,\n    account_tier: account?.tier || null,\n    region: account?.region || null,\n    contract_id: contract?.contract_id || null,\n    renewal_date: contract?.renewal_date || null,\n    support_plan: contract?.support_plan || null,\n    arr_cents: contract?.arr_cents || null,\n    contact_count: contacts.length,\n    contact_roles: contacts.map((item) => item.role).join(\", \"),\n    owner_routing: ownerRouting,\n    recovery_owner: recoveryOwner,\n    risk_signal_count: riskSignals.length,\n    risk_signal_summary: riskSignals.map((item) => item.signal_name).join(\", \"),\n    activity_count: activities.length,\n    audit_timeline: timelineSummary,\n    customer_visible_audit_history: true,\n    opened_at: now,\n    updated_at: now\n  }]);\n\n  replaceRows(db.owner_tasks, request.request_id, ownerGroups.map((group, index) => ({\n    task_id: `task-${request.request_id}-${group.group_order}`,\n    request_id: request.request_id,\n    account_id: request.account_id,\n    owner_group: group.owner_group,\n    group_order: group.group_order,\n    title: ownerTaskTitle(group.owner_group, request.title, account, contract),\n    due_at: addHours(now, OWNER_TASK_DUE_HOURS[group.owner_group] ?? (index + 1) * 12),\n    status: \"open\",\