+      await c.query(
+        "INSERT INTO customer_messages (request_id, account_id, body) VALUES ($1,$2,$3)",
+        [requestId, accountId, body]
+      );
+    }
+
+    // Persist audit_events (always one customer-visible event)
+    const eventText = qualifies
+      ? `Account risk assessment completed. ${signals.length} signal${signals.length > 1 ? "s" : ""} detected. Recovery workflow initiated.`
+      : "Account risk assessment completed. No escalation required. Continuing standard monitoring.";
+    await c.query(
